details:
query text, variables jsonb DEFAULT '{}'::jsonb, "operationName" text DEFAULT NULL::text, extensions jsonb DEFAULT NULL::jsonb RETURNS jsonb AS CREATE OR REPLACE FUNCTION graphql.resolve(query text, variables jsonb DEFAULT '{}'::jsonb, "operationName" text DEFAULT NULL::text, extensions jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
declare
    res jsonb;
    message_text text;
begin
  begin
    select graphql._internal_resolve("query" := "query",
                                     "variables" := "variables",
                                     "operationName" := "operationName",
                                     "extensions" := "extensions") into res;
    return res;
  exception
    when others then
    get stacked diagnostics message_text = message_text;
    return
    jsonb_build_object('data', null,
                       'errors', jsonb_build_array(jsonb_build_object('message', message_text)));
  end;
end;
$function$

 RETURNS trigger AS CREATE OR REPLACE FUNCTION public.calculate_invoice_net_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Always calculate the net_amount for the row being modified
  NEW.net_amount = NEW.amount - COALESCE(NEW.credited_amount, 0);
  RETURN NEW;
END;
$function$

 RETURNS trigger AS CREATE OR REPLACE FUNCTION public.calculate_order_commission()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Only calculate if order has value and primary salesperson
  IF NEW.value IS NOT NULL AND NEW.primary_salesperson_id IS NOT NULL THEN
    -- Get primary salesperson commission rate
    SELECT commission_rate INTO NEW.commission_amount
    FROM user_profiles 
    WHERE id = NEW.primary_salesperson_id AND has_commission = true;

    -- Calculate commission amount (commission_rate is percentage)
    IF NEW.commission_amount IS NOT NULL THEN
      NEW.commission_amount := (NEW.value * NEW.commission_amount / 100);

      -- If there's a secondary salesperson, split the commission
      IF NEW.secondary_salesperson_id IS NOT NULL AND NEW.commission_split_percentage > 0 THEN
        -- The commission_amount will be split between primary and secondary
        -- Primary gets (100 - split_percentage)%, secondary gets split_percentage%
        NULL; -- Commission splitting logic handled in application
      END IF;
    ELSE
      NEW.commission_amount := 0;
    END IF;
  ELSE
    NEW.commission_amount := 0;
  END IF;

  RETURN NEW;
END;
$function$

total_amount numeric, labor_percentage numeric DEFAULT 0.7, rot_percentage numeric DEFAULT 0.5, max_rot_per_person numeric DEFAULT 50000 RETURNS numeric AS CREATE OR REPLACE FUNCTION public.calculate_rot_amount(total_amount numeric, labor_percentage numeric DEFAULT 0.7, rot_percentage numeric DEFAULT 0.5, max_rot_per_person numeric DEFAULT 50000)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  labor_cost numeric;
  rot_deduction numeric;
BEGIN
  -- Calculate labor cost (default 70% of total)
  labor_cost := total_amount * labor_percentage;

  -- Calculate ROT deduction (50% of labor cost)
  rot_deduction := labor_cost * rot_percentage;

  -- Apply maximum limit per person per year
  IF rot_deduction > max_rot_per_person THEN
    rot_deduction := max_rot_per_person;
  END IF;

  RETURN ROUND(rot_deduction, 2);
END;
$function$

 RETURNS trigger AS CREATE OR REPLACE FUNCTION public.calculate_time_log_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Only calculate if we have both start and end time
  IF NEW.start_time IS NOT NULL AND NEW.end_time IS NOT NULL THEN
    -- Calculate total minutes worked (excluding breaks)
    NEW.total_amount := (
      EXTRACT(EPOCH FROM (NEW.end_time - NEW.start_time)) / 60 - COALESCE(NEW.break_duration, 0)
    ) / 60 * NEW.hourly_rate;
  ELSE
    NEW.total_amount := 0;
  END IF;

  NEW.updated_at := now();
  RETURN NEW;
END;
$function$

org_id uuid RETURNS text AS CREATE OR REPLACE FUNCTION public.generate_credit_note_number(org_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$DECLARE
  current_year text;
  next_number integer;
  credit_note_number text;
BEGIN
  current_year := EXTRACT(year FROM CURRENT_DATE)::text;

  -- Get the next number for this year and organization
  SELECT COALESCE(MAX(
    CASE 
      WHEN invoices.credit_note_number ~ ('^KN-' || current_year || '-\d+$') 
      THEN CAST(SUBSTRING(invoices.credit_note_number FROM '\d+$') AS integer)
      ELSE 0 
    END
  ), 0) + 1
  INTO next_number
  FROM invoices 
  WHERE invoices.organisation_id = org_id 
    AND invoices.is_credit_note = true 
    AND invoices.credit_note_number IS NOT NULL;

  credit_note_number := 'KN-' || current_year || '-' || LPAD(next_number::text, 3, '0');

  RETURN credit_note_number;
END;$function$

org_id uuid RETURNS text AS CREATE OR REPLACE FUNCTION public.generate_invoice_number(org_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    current_year INTEGER;
    next_number INTEGER;
    invoice_number TEXT;
BEGIN
    current_year := EXTRACT(YEAR FROM NOW());

    -- Get the highest invoice number for this year and organization
    SELECT COALESCE(
        MAX(
            CASE 
                WHEN invoice_number ~ ('^' || current_year || '-[0-9]+$')
                THEN CAST(SPLIT_PART(invoice_number, '-', 2) AS INTEGER)
                ELSE 0
            END
        ), 0
    ) + 1
    INTO next_number
    FROM invoices 
    WHERE organisation_id = org_id;

    invoice_number := current_year || '-' || LPAD(next_number::TEXT, 4, '0');

    RETURN invoice_number;
END;
$function$

org_id uuid RETURNS text AS CREATE OR REPLACE FUNCTION public.generate_job_number(org_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    current_year integer;
    max_sequence integer;
    new_sequence integer;
    new_job_number text;
BEGIN
    -- Get current year
    current_year := EXTRACT(YEAR FROM NOW());

    -- Find the highest sequence number for this organization and year
    SELECT COALESCE(
        MAX(
            CASE 
                WHEN j.job_number ~ ('^JOBB-' || current_year::text || '-[0-9]{3}$')
                THEN CAST(RIGHT(j.job_number, 3) AS integer)
                ELSE 0
            END
        ), 
        0
    ) INTO max_sequence
    FROM jobs j
    WHERE j.organisation_id = org_id
    AND j.job_number IS NOT NULL;

    -- Increment sequence
    new_sequence := max_sequence + 1;

    -- Format the new job number
    new_job_number := 'JOBB-' || current_year::text || '-' || LPAD(new_sequence::text, 3, '0');

    RETURN new_job_number;
END;
$function$

org_id uuid RETURNS text AS CREATE OR REPLACE FUNCTION public.generate_quote_number(org_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    current_year text;
    next_seq_val int;
    quote_num text;
BEGIN
    current_year := to_char(now(), 'YYYY');

    -- Find the maximum existing sequence number for the current year and organization
    -- and increment it. COALESCE handles the case where no quotes exist yet.
    SELECT COALESCE(MAX(SUBSTRING(quote_number FROM '[0-9]+$')::int), 0) + 1
    INTO next_seq_val
    FROM public.quotes
    WHERE organisation_id = org_id
      AND quote_number LIKE 'OFF-' || current_year || '-%';

    -- Format the quote number with leading zeros for the sequence part
    quote_num := 'OFF-' || current_year || '-' || LPAD(next_seq_val::text, 3, '0');

    RETURN quote_num;
END;
$function$

org_id uuid RETURNS jsonb AS CREATE OR REPLACE FUNCTION public.get_dashboard_stats(org_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    result jsonb;
    orders_total numeric;
    leads_by_status jsonb;
    jobs_by_status jsonb;
    current_month_start date;
    current_month_end date;
BEGIN
    -- Calculate current month boundaries
    current_month_start := date_trunc('month', CURRENT_DATE)::date;
    current_month_end := (date_trunc('month', CURRENT_DATE) + interval '1 month' - interval '1 day')::date;

    -- Sum of total_amount from orders for current month
    SELECT COALESCE(SUM(total_amount), 0)
    INTO orders_total
    FROM orders
    WHERE organisation_id = org_id
      AND created_at >= current_month_start
      AND created_at <= current_month_end;

    -- Count of leads by status
    SELECT COALESCE(
        jsonb_object_agg(status, cnt),
        '{}'::jsonb
    )
    INTO leads_by_status
    FROM (
        SELECT status, COUNT(*) as cnt
        FROM leads
        WHERE organisation_id = org_id
        GROUP BY status
    ) lead_counts;

    -- Count of jobs by status
    SELECT COALESCE(
        jsonb_object_agg(status, cnt),
        '{}'::jsonb
    )
    INTO jobs_by_status
    FROM (
        SELECT status, COUNT(*) as cnt
        FROM jobs
        WHERE organisation_id = org_id
        GROUP BY status
    ) job_counts;

    -- Build result JSON
    result := jsonb_build_object(
        'orders_total_this_month', orders_total,
        'leads_by_status', leads_by_status,
        'jobs_by_status', jobs_by_status
    );

    RETURN result;
END;
$function$

 RETURNS trigger AS CREATE OR REPLACE FUNCTION public.populate_invoice_from_order()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- If order_id is provided, copy team and job data from the order
  IF NEW.order_id IS NOT NULL THEN
    UPDATE invoices SET
      assigned_team_id = COALESCE(NEW.assigned_team_id, (
        SELECT assigned_to_team_id FROM orders WHERE id = NEW.order_id
      )),
      assigned_user_id = COALESCE(NEW.assigned_user_id, (
        SELECT assigned_to_user_id FROM orders WHERE id = NEW.order_id
      )),
      job_description = COALESCE(NEW.job_description, (
        SELECT job_description FROM orders WHERE id = NEW.order_id
      )),
      job_type = COALESCE(NEW.job_type, (
        SELECT job_type FROM orders WHERE id = NEW.order_id
      ))
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
END;
$function$

