 RETURNS trigger AS CREATE OR REPLACE FUNCTION public.update_invoice_rot_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.include_rot = true AND NEW.amount > 0 THEN
    NEW.rot_amount := calculate_rot_amount(NEW.amount);
  ELSE
    NEW.rot_amount := 0;
  END IF;

  RETURN NEW;
END;
$function$

